import { cache } from "react";
import { cookies } from "next/headers";

export const igrpGetSession = cache(async () => {
  const c = await cookies();
  const token = c.get("igrp.session")?.value;
  if (!token) return null;
  return fetchSession(token);
});
// Now multiple Server Components in the same request share one network call.

// Static marketing-like data — long revalidate is fine
const res = await fetch(`${base}/config/layout`, {
  next: { revalidate: 3600, tags: ["layout-config"] },
});

// Per-request user data — always fresh
const res = await fetch(`${base}/me`, {
  cache: "no-store",
  headers: { authorization: `Bearer ${token}` },
});
// Be explicit. Never leave the decision to the default.
